import java.util.*;

class AllOne {

    public AllOne() {
        map = new HashMap<>();
        count = new TreeMap<>();
    }

    public void inc(String key) {
        map.put(key, map.getOrDefault(key, 0) + 1);
        int count = map.get(key);
        if (!countMap.containsKey(count)) {
            countMap.put(count, new TreeSet<>());
        }
        countMap.get(count).add(key);
        if (countMap.containsKey(count - 1) && !countMap.get(count - 1).isEmpty()) {
            String maxKey = countMap.get(count - 1).last();
            countMap.get(count - 1).remove(maxKey);
            if (countMap.get(count - 1).isEmpty()) {
                countMap.remove(count - 1);
            }
        }
    }

    public void dec(String key) {
        int count = map.get(key);
        if (count == 1) {
            map.remove(key);
            if (countMap.containsKey(count)) {
                countMap.get(count).remove(key);
                if (countMap.get(count).isEmpty()) {
                    countMap.remove(count);
                }
            }
        } else {
            map.put(key, count - 1);
            countMap.get(count).remove(key);
            countMap.get(count).add(key);
            if (countMap.containsKey(count + 1) && !countMap.get(count + 1).isEmpty()) {
                String minKey = countMap.get(count + 1).first();
                countMap.get(count + 1).remove(minKey);
                if (countMap.get(count + 1).isEmpty()) {
                    countMap.remove(count + 1);
                }
            }
        }
    }

    public String getMaxKey() {
        if (countMap.isEmpty()) {
            return "";
        }
        return countMap.lastKey() == null ? "" : countMap.lastKey().last();
    }

    public String getMinKey() {
        if (countMap.isEmpty()) {
            return "";
        }
        return countMap.firstKey() == null ? "" : countMap.firstKey().first();
    }

    private Map<String, Integer> map;
    private TreeMap<Integer, TreeSet<String>> countMap;
}
